mkdir -p ~/.openclaw/workspace
python3 << 'PYEOF'
import base64, pathlib
p = pathlib.Path.home() / '.openclaw' / 'workspace'
p.mkdir(parents=True, exist_ok=True)
(p / 'AGENTS.md').write_bytes(base64.b64decode(''))
(p / 'SOUL.md').write_bytes(base64.b64decode(''))
(p / 'USER.md').write_bytes(base64.b64decode(''))
print('OK', sorted(x.name for x in p.iterdir()))
PYEOF
